// Use node references with proper defaults for missing files
let metrics = { 
  signals: [], 
  accuracy: { overall: 0, by_type: {} },
  last_updated: null
};
let patterns = { 
  patterns: [], 
  threshold_adjustments: {
    rsi_oversold: 30,
    rsi_overbought: 70,
    volume_spike_multiplier: 1.5
  },
  confidence_weights: {
    rsi: 0.40,
    macd: 0.20,
    volume: 0.15,
    momentum: 0.15,
    bollinger: 0.10
  },
  risk_parameters: {
    stop_loss_pct: 6.0,
    take_profit_pct: 8.0,
    trailing_stop_pct: 4.0
  }
};
let positions = {};

try {
  const metricsItem = $('Load Metrics').first();
  if (metricsItem?.binary?.data?.data) {
    metrics = JSON.parse(Buffer.from(metricsItem.binary.data.data, 'base64').toString('utf-8'));
    // Ensure structure exists
    if (!metrics.accuracy) metrics.accuracy = { overall: 0, by_type: {} };
    if (!metrics.signals) metrics.signals = [];
  }
} catch (e) {
  console.log('Metrics file not found or invalid, using defaults');
}

try {
  const patternsItem = $('Load Patterns').first();
  if (patternsItem?.binary?.data?.data) {
    patterns = JSON.parse(Buffer.from(patternsItem.binary.data.data, 'base64').toString('utf-8'));
    // Merge with defaults
    patterns.threshold_adjustments = { ...patterns.threshold_adjustments, ...(patterns.threshold_adjustments || {}) };
    patterns.confidence_weights = { ...patterns.confidence_weights, ...(patterns.confidence_weights || {}) };
  }
} catch (e) {
  console.log('Patterns file not found or invalid, using defaults');
}

try {
  const positionsItem = $('Load Positions').first();
  if (positionsItem?.binary?.data?.data) {
    const parsed = JSON.parse(Buffer.from(positionsItem.binary.data.data, 'base64').toString('utf-8'));
    positions = parsed.positions || {};
  }
} catch (e) {
  console.log('Positions file not found or invalid, using empty defaults');
}

return [{ json: { metrics, patterns, positions, timestamp: new Date().toISOString() } }];

const input = $input.first().json;
const metrics = input.metrics || {};
const positions = input.positions || {};
const patterns = input.patterns || {};
const timestamp = input.timestamp;

// Calculate signal accuracy
const signals = metrics.signals || [];
const evaluatedSignals = signals.filter(s => s.outcome && s.outcome !== 'pending');
const correctSignals = evaluatedSignals.filter(s => s.outcome === 'correct');
const overallAccuracy = evaluatedSignals.length > 0
  ? Math.round((correctSignals.length / evaluatedSignals.length) * 100)
  : 50;

// Analyze accuracy by signal type
const byType = {};
const signalTypes = ['stop_loss', 'take_profit', 'rsi_oversold', 'rsi_overbought', 'macd_cross', 'volume_spike'];

for (const type of signalTypes) {
  const typeSignals = signals.filter(s => 
    s.tech_reasons?.some(r => r.toLowerCase().includes(type.replace('_', ' ')))
  );
  const evaluated = typeSignals.filter(s => s.outcome && s.outcome !== 'pending');
  const correct = evaluated.filter(s => s.outcome === 'correct').length;

  byType[type] = {
    correct,
    total: evaluated.length,
    rate: evaluated.length > 0 ? Math.round((correct / evaluated.length) * 100) : 50
  };
}

// Build learning summary for AI
const summary = [];
summary.push('=== LEARNING ANALYSIS ===');
summary.push(`Overall Signal Accuracy: ${overallAccuracy}%`);
summary.push(`Total Signals: ${signals.length}`);
summary.push(`Evaluated: ${evaluatedSignals.length}`);
summary.push(`Pending: ${signals.filter(s => !s.outcome || s.outcome === 'pending').length}`);
summary.push('');
summary.push('Accuracy by Type:');
for (const [type, data] of Object.entries(byType)) {
  if (data.total > 0) {
    summary.push(`  ${type}: ${data.rate}% (${data.correct}/${data.total})`);
  }
}
summary.push('');

// Current thresholds
summary.push('Current Thresholds:');
const thresholds = patterns.threshold_adjustments || {};
summary.push(`  RSI Oversold: ${thresholds.rsi_oversold || 30}`);
summary.push(`  RSI Overbought: ${thresholds.rsi_overbought || 70}`);
summary.push(`  Volume Spike Multiplier: ${thresholds.volume_spike_multiplier || 1.5}`);

return [{
  json: {
    summary: summary.join('\n'),
    overallAccuracy,
    accuracyByType: byType,
    signalCount: signals.length,
    evaluatedCount: evaluatedSignals.length,
    currentThresholds: thresholds,
    signals,
    timestamp
  }
}];

// Ollama unavailable - use rule-based adjustments
const analyzeData = $('Analyze Performance').first().json;
const currentThresholds = analyzeData.currentThresholds || {};
const accuracyByType = analyzeData.accuracyByType || {};

// Rule-based adjustments (no AI)
const adjustments = { ...currentThresholds };

for (const [type, data] of Object.entries(accuracyByType)) {
  if (data.total < 5) continue; // Not enough samples

  if (data.rate < 40) {
    // Tighten threshold
    if (type.includes('rsi_oversold')) adjustments.rsi_oversold = Math.max(20, (adjustments.rsi_oversold || 30) - 3);
    if (type.includes('rsi_overbought')) adjustments.rsi_overbought = Math.min(80, (adjustments.rsi_overbought || 70) + 3);
    if (type.includes('volume')) adjustments.volume_spike_multiplier = Math.min(3.0, (adjustments.volume_spike_multiplier || 1.5) + 0.2);
  } else if (data.rate > 70) {
    // Loosen threshold
    if (type.includes('rsi_oversold')) adjustments.rsi_oversold = Math.min(35, (adjustments.rsi_oversold || 30) + 2);
    if (type.includes('rsi_overbought')) adjustments.rsi_overbought = Math.max(65, (adjustments.rsi_overbought || 70) - 2);
    if (type.includes('volume')) adjustments.volume_spike_multiplier = Math.max(1.2, (adjustments.volume_spike_multiplier || 1.5) - 0.1);
  }
}

// Cap adjustments at ±20% from defaults
const defaults = { rsi_oversold: 30, rsi_overbought: 70, volume_spike_multiplier: 1.5 };
for (const key of Object.keys(adjustments)) {
  const def = defaults[key] || adjustments[key];
  const maxChange = def * 0.2;
  adjustments[key] = Math.max(def - maxChange, Math.min(def + maxChange, adjustments[key]));
}

return [{
  json: {
    summary: analyzeData.summary,
    adjustments,
    reasoning: 'Rule-based fallback (Ollama unavailable)',
    patternsToWatch: [],
    patternsToAvoid: [],
    fallbackMode: true
  }
}];

const input = $input.first().json;
const analyzeData = $('Analyze Performance').first().json;
const currentThresholds = analyzeData.currentThresholds || {};

// Parse AI response
let adjustments = {
  rsi_oversold: currentThresholds.rsi_oversold || 30,
  rsi_overbought: currentThresholds.rsi_overbought || 70,
  volume_spike_multiplier: currentThresholds.volume_spike_multiplier || 1.5
};
let reasoning = '';
let patternsToWatch = [];
let patternsToAvoid = [];

try {
  const aiText = input.output || input.text || '';
  const jsonMatch = aiText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.adjustments) {
      adjustments = {
        rsi_oversold: parsed.adjustments.rsi_oversold || adjustments.rsi_oversold,
        rsi_overbought: parsed.adjustments.rsi_overbought || adjustments.rsi_overbought,
        volume_spike_multiplier: parsed.adjustments.volume_spike_multiplier || adjustments.volume_spike_multiplier
      };
    }
    reasoning = parsed.reasoning || '';
    patternsToWatch = parsed.patterns_to_watch || [];
    patternsToAvoid = parsed.patterns_to_avoid || [];
  }
} catch (e) {
  // Keep defaults if AI response parsing fails
}

// Preserve signal history from Parse Data
const parseData = $('Parse Data').first().json;

// Build updated metrics
const updatedMetrics = {
  signals: parseData.metrics.signals || [],
  accuracy: {
    overall: analyzeData.overallAccuracy,
    by_type: analyzeData.accuracyByType
  },
  last_updated: analyzeData.timestamp
};

// Build updated patterns
const updatedPatterns = {
  patterns: [
    {
      name: 'rsi_oversold_bounce',
      conditions: ['rsi_14 < ' + adjustments.rsi_oversold, 'volume > avg_volume'],
      action: 'buy',
      success_rate: (analyzeData.accuracyByType?.rsi_oversold?.rate || 50) / 100,
      samples: analyzeData.accuracyByType?.rsi_oversold?.total || 0
    },
    {
      name: 'rsi_overbought_reversal',
      conditions: ['rsi_14 > ' + adjustments.rsi_overbought, 'volume > avg_volume'],
      action: 'sell',
      success_rate: (analyzeData.accuracyByType?.rsi_overbought?.rate || 50) / 100,
      samples: analyzeData.accuracyByType?.rsi_overbought?.total || 0
    }
  ],
  threshold_adjustments: adjustments,
  patterns_to_watch: patternsToWatch,
  patterns_to_avoid: patternsToAvoid,
  reasoning: reasoning,
  last_updated: analyzeData.timestamp
};

// Create binary data for file writing
const metricsBinary = Buffer.from(JSON.stringify(updatedMetrics, null, 2)).toString('base64');
const patternsBinary = Buffer.from(JSON.stringify(updatedPatterns, null, 2)).toString('base64');

return [{
  json: {
    metrics: updatedMetrics,
    patterns: updatedPatterns,
    summary: {
      accuracy: analyzeData.overallAccuracy + '%',
      signals_analyzed: analyzeData.evaluatedCount,
      threshold_changes: JSON.stringify(adjustments),
      reasoning: reasoning
    }
  },
  binary: {
    metrics_data: {
      data: metricsBinary,
      mimeType: 'application/json',
      fileName: 'metrics.json'
    },
    patterns_data: {
      data: patternsBinary,
      mimeType: 'application/json',
      fileName: 'patterns.json'
    }
  }
}];

